  1→import React, {useCallback, useState} from 'react';
  2→import {ActivityIndicator, Alert, StyleSheet, View} from 'react-native';
  3→import {useQuery} from '@tanstack/react-query';
  4→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
  5→import {CompositeScreenProps} from '@react-navigation/native';
  6→import {NativeStackScreenProps} from '@react-navigation/native-stack';
  7→import {SafeAreaView} from 'react-native-safe-area-context';
  8→import {useAuth} from '../../features/auth/AuthProvider';
  9→import {useTheme} from '../../theme/ThemeProvider';
 10→import {mobileApi} from '../../lib/api/mobileApi';
 11→import {ProfileHeroSection} from './ProfileHeroSection';
 12→import {ProfileTabBar, type ProfileTab} from './ProfileTabBar';
 13→import {ProfileWritingsTab} from './ProfileWritingsTab';
 14→import {ProfileStoriesTab} from './ProfileStoriesTab';
 15→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 16→
 17→type Props = CompositeScreenProps<
 18→  BottomTabScreenProps<MainTabParamList, 'Profile'>,
 19→  NativeStackScreenProps<RootStackParamList>
 20→>;
 21→
 22→export function ProfileScreen({navigation}: Props) {
 23→  const {user, signOut} = useAuth();
 24→  const {colors} = useTheme();
 25→  const [activeTab, setActiveTab] = useState<ProfileTab>('writings');
 26→
 27→  const userDataQuery = useQuery({
 28→    queryKey: ['profile', user?.id],
 29→    enabled: Boolean(user?.id),
 30→    queryFn: () => mobileApi.getUserData(user?.id ?? ''),
 31→  });
 32→
 33→  const streakQuery = useQuery({
 34→    queryKey: ['streak', user?.id],
 35→    enabled: Boolean(user?.id),
 36→    queryFn: () => mobileApi.getStreak(user?.id ?? ''),
 37→  });
 38→
 39→  const profile = userDataQuery.data?.userData?.[0] ?? null;
 40→  const streak = streakQuery.data?.currentStreak;
 41→
 42→  const onSettingsPress = useCallback(() => {
 43→    Alert.alert('Sign Out', 'Are you sure you want to sign out?', [
 44→      {text: 'Cancel', style: 'cancel'},
 45→      {
 46→        text: 'Sign Out',
 47→        style: 'destructive',
 48→        onPress: async () => {
 49→          try {
 50→            await signOut();
 51→          } catch (error) {
 52→            Alert.alert(
 53→              'Sign out failed',
 54→              error instanceof Error ? error.message : 'Unknown error',
 55→            );
 56→          }
 57→        },
 58→      },
 59→    ]);
 60→  }, [signOut]);
 61→
