    modal: Platform.select({
      ios: {
        shadowColor: colors.bgPrimary === '#FAF9F6' ? 'rgba(80,60,40,0.15)' : 'rgba(0,0,0,0.6)',
        shadowOffset: {width: 0, height: 8},
        shadowOpacity: 1,
        shadowRadius: 32,
