 66→      <View
 67→        style={[
 68→          styles.ring,
 69→          {
 70→            width: ringSize,
 71→            height: ringSize,
 72→            borderRadius: ringSize / 2,
 73→            borderColor: ringColor,
 74→          },
 75→        ]}>
 76→        {content}
 77→      </View>
 78→    );
 79→  }
 80→
 81→  return content;
 82→}
