 85→            data={[]}
 86→            renderItem={null}
 87→            showsVerticalScrollIndicator={false}
 88→            contentContainerStyle={styles.results}
 89→            ListHeaderComponent={
 90→              <>
 91→                {/* Users section */}
 92→                {activeTab !== 'posts' && users.length > 0 && (
