 31→        before: pageParam ?? null,
 32→      }),
 33→    initialPageParam: null as string | null,
 34→    getNextPageParam: lastPage => {
 35→      if (!lastPage.hasMore || lastPage.data.length < PAGE_SIZE) return undefined;
 36→      const last = lastPage.data[lastPage.data.length - 1];
 37→      return last?.created_at ?? undefined;
 38→    },
 39→  });
 40→
 41→  const stories = useMemo(
