 32→const extractBearerToken = (authHeader = "") => {
 33→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 34→    if (!trimmed) return "";
 35→
 36→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 37→    if (bearerMatch?.[1]) {
 38→        return bearerMatch[1].trim();
