 37→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 38→
 39→type Props = CompositeScreenProps<
 40→  BottomTabScreenProps<MainTabParamList, 'Home'>,
 41→  NativeStackScreenProps<RootStackParamList>
 42→>;
 43→
 44→const PAGE_SIZE = 10;
 45→
 46→const QUICK_ACTIONS = [
 47→  {key: 'all', label: 'All'},
 48→  {key: 'journal', label: 'Journals'},
 49→  {key: 'canvas', label: 'Canvas'},
 50→  {key: 'freedom_wall', label: 'Freedom Wall'},
 51→  {key: 'universe', label: 'Universe'},
 52→] as const;
 53→
 54→export function HomeFeedScreen({navigation}: Props) {
 55→  const {user, session} = useAuth();
 56→  const {colors} = useTheme();
 57→  const token = session?.access_token ?? '';
 58→  const [refreshing, setRefreshing] = useState(false);
 59→  const [activeFilter, setActiveFilter] = useState('all');
 60→
 61→  const feedQuery = useInfiniteQuery({
 62→    queryKey: ['feed', user?.id],
 63→    queryFn: ({pageParam}) =>
 64→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 65→    initialPageParam: null as string | null,
 66→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 67→  });
 68→
 69→  const reactionMutation = useMutation({
 70→    mutationFn: async ({
 71→      journalId,
 72→      receiverId,
 73→      reactionType,
 74→    }: {
 75→      journalId: string;
 76→      receiverId: string;
 77→      reactionType: string;
 78→    }) => {
 79→      if (!token) throw new Error('Please log in to react.');
 80→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 81→    },
 82→    onMutate: async ({journalId, reactionType}) => {
 83→      await queryClient.cancelQueries({queryKey: ['feed']});
 84→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 85→        ['feed', user?.id],
 86→      );
 87→      if (prev) {
 88→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 89→          ['feed', user?.id],
 90→          old => {
 91→            if (!old) return old;
 92→            return {
 93→              ...old,
 94→              pages: old.pages.map(page => ({
 95→                ...page,
 96→                data: page.data.map(item => {
 97→                  if (item.id !== journalId) return item;
 98→                  const removing = item.user_reaction === reactionType;
 99→                  const currentCount =
100→                    (item.reaction_count?.[0]?.count ??
101→                      item.like_count?.[0]?.count ??
102→                      item.likes_count ??
103→                      0) as number;
104→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
105→                  return {
106→                    ...item,
107→                    user_reaction: removing ? null : reactionType,
108→                    has_liked: removing ? false : true,
109→                    like_count: [{count: Math.max(0, currentCount + delta)}],
110→                  };
111→                }),
112→              })),
113→            };
114→          },
115→        );
116→      }
117→      return {prev};
118→    },
119→    onError: (_err, _vars, context) => {
120→      if (context?.prev) {
121→        queryClient.setQueryData(['feed', user?.id], context.prev);
122→      }
123→    },
124→    onSettled: () => {
125→      queryClient.invalidateQueries({queryKey: ['feed']});
126→    },
127→  });
128→
129→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
130→    if (!token) return;
131→    reactionMutation.mutate({journalId, receiverId, reactionType});
132→  };
133→
134→  const posts = useMemo(
135→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
136→    [feedQuery.data?.pages],
137→  );
138→
139→  const onRefresh = async () => {
140→    setRefreshing(true);
141→    try {
142→      await feedQuery.refetch();
143→    } finally {
144→      setRefreshing(false);
145→    }
146→  };
147→
148→  const handleQuickAction = (key: string) => {
149→    if (key === 'canvas') {
150→      navigation.navigate('Canvas');
151→    } else if (key === 'freedom_wall') {
152→      navigation.navigate('FreedomWall');
153→    } else if (key === 'universe') {
154→      navigation.navigate('Universe');
155→    } else {
156→      setActiveFilter(key);
157→    }
158→  };
159→
160→  return (
161→    <SafeAreaView
162→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
163→      edges={['top']}>
164→      {/* Branded header */}
165→      <View
166→        style={[
167→          styles.header,
168→          {borderBottomColor: colors.borderCard},
169→        ]}>
170→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
171→          iskrib
172→        </Text>
173→      </View>
174→
175→      {/* Filter chips */}
176→      <View style={styles.chipRow}>
177→        <ScrollView
178→          horizontal
179→          showsHorizontalScrollIndicator={false}
180→          contentContainerStyle={styles.chipScroll}>
181→          {QUICK_ACTIONS.map(action => (
182→            <Chip
183→              key={action.key}
184→              label={action.label}
185→              active={activeFilter === action.key}
186→              onPress={() => handleQuickAction(action.key)}
187→            />
188→          ))}
189→        </ScrollView>
190→      </View>
191→
192→      {/* Feed */}
193→      <FlatList
194→        data={posts}
195→        onRefresh={onRefresh}
196→        refreshing={refreshing}
197→        onEndReachedThreshold={0.25}
198→        onEndReached={() => {
199→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
200→            feedQuery.fetchNextPage();
201→          }
202→        }}
203→        contentContainerStyle={styles.listContent}
204→        showsVerticalScrollIndicator={false}
205→        ListEmptyComponent={
