512→
513→        {/* Comment input */}
514→        {token ? (
515→          <View style={styles.commentInputRow}>
516→            {replyingTo && (
517→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
518→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
