  1→import React, {useCallback, useMemo, useState} from 'react';
  2→import {ActivityIndicator, Alert, Image, StyleSheet, View} from 'react-native';
  3→import {useQuery} from '@tanstack/react-query';
  4→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
  5→import {CompositeScreenProps} from '@react-navigation/native';
  6→import {NativeStackScreenProps} from '@react-navigation/native-stack';
  7→import {SafeAreaView} from 'react-native-safe-area-context';
  8→import LinearGradient from 'react-native-linear-gradient';
  9→import {useAuth} from '../../features/auth/AuthProvider';
 10→import {useTheme} from '../../theme/ThemeProvider';
 11→import {mobileApi} from '../../lib/api/mobileApi';
 12→import {ProfileHeroSection} from './ProfileHeroSection';
 13→import {ProfileTabBar, type ProfileTab} from './ProfileTabBar';
 14→import {ProfileWritingsTab} from './ProfileWritingsTab';
 15→import {ProfileStoriesTab} from './ProfileStoriesTab';
 16→import {
 17→  parseProfileBackground,
 18→  cssAngleToGradientPoints,
 19→} from '../../lib/utils/profileBackground';
 20→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 21→
 22→type Props = CompositeScreenProps<
 23→  BottomTabScreenProps<MainTabParamList, 'Profile'>,
 24→  NativeStackScreenProps<RootStackParamList>
 25→>;
 26→
 27→export function ProfileScreen({navigation}: Props) {
 28→  const {user, signOut} = useAuth();
 29→  const {colors} = useTheme();
 30→  const [activeTab, setActiveTab] = useState<ProfileTab>('writings');
 31→
 32→  const userDataQuery = useQuery({
 33→    queryKey: ['profile', user?.id],
 34→    enabled: Boolean(user?.id),
 35→    queryFn: () => mobileApi.getUserData(user?.id ?? ''),
 36→  });
 37→
 38→  const streakQuery = useQuery({
 39→    queryKey: ['streak', user?.id],
 40→    enabled: Boolean(user?.id),
 41→    queryFn: () => mobileApi.getStreak(user?.id ?? ''),
 42→  });
 43→
 44→  const profile = userDataQuery.data?.userData?.[0] ?? null;
 45→  const streak = streakQuery.data?.currentStreak;
 46→
 47→  const parsedBg = useMemo(
 48→    () => parseProfileBackground(profile?.background),
 49→    [profile?.background],
 50→  );
 51→
 52→  const onSettingsPress = useCallback(() => {
 53→    Alert.alert('Sign Out', 'Are you sure you want to sign out?', [
 54→      {text: 'Cancel', style: 'cancel'},
 55→      {
 56→        text: 'Sign Out',
 57→        style: 'destructive',
 58→        onPress: async () => {
 59→          try {
 60→            await signOut();
 61→          } catch (error) {
 62→            Alert.alert(
 63→              'Sign out failed',
 64→              error instanceof Error ? error.message : 'Unknown error',
 65→            );
 66→          }
 67→        },
 68→      },
 69→    ]);
 70→  }, [signOut]);
 71→
 72→  const onEditProfile = useCallback(() => {
 73→    navigation.navigate('EditProfile');
 74→  }, [navigation]);
 75→
 76→  const onFollowersPress = useCallback(() => {
 77→    if (user?.id) {
 78→      navigation.navigate('FollowList', {userId: user.id, tab: 'followers'});
 79→    }
 80→  }, [navigation, user?.id]);
 81→
 82→  const onFollowingPress = useCallback(() => {
 83→    if (user?.id) {
 84→      navigation.navigate('FollowList', {userId: user.id, tab: 'following'});
 85→    }
 86→  }, [navigation, user?.id]);
 87→
 88→  if (userDataQuery.isLoading) {
 89→    return (
 90→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
 91→        <View style={styles.loadingContainer}>
 92→          <ActivityIndicator color={colors.loaderColor} size="large" />
 93→        </View>
 94→      </SafeAreaView>
 95→    );
 96→  }
 97→
 98→  const headerComponent = (
 99→    <View>
100→      <ProfileHeroSection
101→        profile={profile}
102→        streak={streak}
103→        email={user?.email}
104→        onEditProfile={onEditProfile}
105→        onSettingsPress={onSettingsPress}
106→        onFollowersPress={onFollowersPress}
107→        onFollowingPress={onFollowingPress}
108→      />
109→      <ProfileTabBar activeTab={activeTab} onTabChange={setActiveTab} />
110→      <View style={styles.tabSpacer} />
111→    </View>
112→  );
113→
114→  const backdropElement = useMemo(() => {
115→    if (parsedBg.type === 'gradient') {
116→      const {start, end} = cssAngleToGradientPoints(parsedBg.angle);
117→      return (
118→        <LinearGradient
119→          colors={parsedBg.colors}
120→          locations={parsedBg.locations}
121→          start={start}
122→          end={end}
123→          style={[StyleSheet.absoluteFill, styles.backdrop]}
124→        />
125→      );
126→    }
127→    if (parsedBg.type === 'image') {
128→      const dominantArr = profile?.dominant_colors
129→        ? profile.dominant_colors.split(',').map(c => c.trim())
130→        : null;
131→      const secondaryArr = profile?.secondary_colors
132→        ? profile.secondary_colors.split(',').map(c => c.trim())
133→        : null;
134→      const hasGradientOverlay =
135→        dominantArr && dominantArr.length > 0 && secondaryArr && secondaryArr.length > 0;
136→      return (
137→        <View style={[StyleSheet.absoluteFill, styles.backdrop]}>
138→          {hasGradientOverlay && (
139→            <LinearGradient
140→              colors={[...dominantArr, ...secondaryArr]}
141→              style={StyleSheet.absoluteFill}
142→            />
143→          )}
144→          <Image
145→            source={{uri: parsedBg.uri}}
146→            blurRadius={40}
147→            style={[StyleSheet.absoluteFill, {opacity: 0.3}]}
148→            resizeMode="cover"
149→          />
150→        </View>
151→      );
152→    }
153→    return null;
154→  }, [parsedBg, profile?.dominant_colors, profile?.secondary_colors]);
155→
156→  return (
157→    <SafeAreaView
158→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
159→      edges={['top']}>
160→      {backdropElement}
161→
162→      {activeTab === 'writings' ? (
163→        <ProfileWritingsTab
164→          userId={user?.id ?? ''}
165→          headerComponent={headerComponent}
166→        />
167→      ) : (
168→        <ProfileStoriesTab
169→          userId={user?.id ?? ''}
170→          headerComponent={headerComponent}
171→        />
172→      )}
173→    </SafeAreaView>
174→  );
175→}
