177→const styles = StyleSheet.create({
178→  safe: {
179→    flex: 1,
180→  },
181→  loadingContainer: {
182→    flex: 1,
183→    alignItems: 'center',
184→    justifyContent: 'center',
185→  },
186→  tabSpacer: {
187→    height: 12,
188→  },
189→  backdrop: {
190→    opacity: 0.15,
191→    transform: [{scale: 1.4}],
192→  },
193→});
