  1→import React, {useMemo} from 'react';
  2→import {FlatList, StyleSheet, View} from 'react-native';
  3→import {useInfiniteQuery} from '@tanstack/react-query';
  4→import {useNavigation} from '@react-navigation/native';
  5→import type {NativeStackNavigationProp} from '@react-navigation/native-stack';
  6→import {PostCardSkeleton} from '../../components/SkeletonLoader';
  7→import {EmptyState} from '../../components/EmptyState';
  8→import {storyApi} from '../../lib/api/storyApi';
  9→import {useAuth} from '../../features/auth/AuthProvider';
 10→import {spacing} from '../../theme/spacing';
 11→import {ProfileStoryCard} from './ProfileStoryCard';
 12→import type {RootStackParamList} from '../../navigation/types';
 13→
 14→const PAGE_SIZE = 10;
 15→
 16→interface ProfileStoriesTabProps {
 17→  userId: string;
 18→  headerComponent?: React.ReactElement;
 19→}
 20→
 21→export function ProfileStoriesTab({userId, headerComponent}: ProfileStoriesTabProps) {
 22→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 23→  const {session} = useAuth();
 24→  const token = session?.access_token;
 25→
 26→  const query = useInfiniteQuery({
 27→    queryKey: ['profileStories', userId],
 28→    queryFn: ({pageParam}) =>
 29→      storyApi.getUserStories(userId, token ?? undefined, {
 30→        limit: PAGE_SIZE,
 31→        before: pageParam ?? null,
 32→      }),
 33→    initialPageParam: null as string | null,
 34→    getNextPageParam: lastPage => {
 35→      if (!lastPage.hasMore || lastPage.data.length < PAGE_SIZE) return undefined;
 36→      const last = lastPage.data[lastPage.data.length - 1];
 37→      return last?.created_at ?? undefined;
 38→    },
 39→  });
 40→
 41→  const stories = useMemo(
 42→    () => query.data?.pages.flatMap(page => page.data ?? []) ?? [],
 43→    [query.data?.pages],
 44→  );
 45→
 46→  return (
 47→    <FlatList
 48→      data={stories}
 49→      keyExtractor={item => item.id}
 50→      showsVerticalScrollIndicator={false}
 51→      contentContainerStyle={styles.list}
 52→      ListHeaderComponent={headerComponent}
 53→      onEndReachedThreshold={0.3}
 54→      onEndReached={() => {
 55→        if (query.hasNextPage && !query.isFetchingNextPage) {
 56→          query.fetchNextPage();
 57→        }
 58→      }}
 59→      ListEmptyComponent={
 60→        query.isLoading ? (
 61→          <View style={styles.skeletons}>
 62→            <PostCardSkeleton />
 63→            <PostCardSkeleton />
 64→          </View>
 65→        ) : (
 66→          <EmptyState
 67→            title="No stories yet"
 68→            subtitle="Published stories will appear here."
 69→          />
 70→        )
 71→      }
 72→      ListFooterComponent={
 73→        query.isFetchingNextPage ? (
 74→          <View style={styles.footer}>
 75→            <PostCardSkeleton />
 76→          </View>
 77→        ) : null
 78→      }
 79→      renderItem={({item}) => (
 80→        <ProfileStoryCard
 81→          story={item}
 82→          onPress={() => navigation.navigate('StoryDetail', {storyId: item.id})}
 83→        />
 84→      )}
 85→      ItemSeparatorComponent={() => <View style={styles.separator} />}
 86→    />
 87→  );
 88→}
