161→
162→  async deleteNotification(
163→    token: string,
164→    notifId: string,
165→    source?: NotificationSource,
166→  ): Promise<{message?: string}> {
167→    const suffix = source
168→      ? `/deleteNotification/${encodeURIComponent(notifId)}?source=${encodeURIComponent(source)}`
169→      : `/deleteNotification/${encodeURIComponent(notifId)}`;
170→
171→    return apiRequest<{message?: string}>(suffix, {
172→      method: 'DELETE',
173→      headers: {
174→        ...authHeaders(token),
175→      },
