184→    const params = new URLSearchParams();
185→    params.set('limit', String(limit));
186→    if (cursor) {
187→      params.set('before', cursor);
188→    }
189→
190→    return apiRequest<CursorPage<unknown>>(`/getUnreadNotification?${params.toString()}`, {
191→      method: 'GET',
192→      headers: {
193→        ...authHeaders(token),
194→      },
195→    });
196→  },
